FULL RESPONSE FOR DEBUGGING: ```json
{
  "definitions": [
    {
      "term": "A-Side / B-Side Control",
      "definition": "A dual-authorization requirement where two separate individuals (e.g., Client and Co-Signer, or Banker and Manager) must provide distinct cryptographic signatures.",
      "policyContext": "BC-SEC-001, BC-SEC-002"
    },
    {
      "term": "Active Liquidity",
      "definition": "The portion of the account balance held in the Flagship Cash Account (BC-PROD-001) that is not currently pledged as collateral.",
      "policyContext": "BC-PROD-001, BC-PROD-003"
    },
    {
      "term": "Audit Receipt",
      "definition": "A cryptographically signed digital record issued to the client after a Material Event, containing specific JSON headers for automated reconciliation.",
      "policyContext": "All BC-series policies, Appendix C"
    },
    {
      "term": "The Biscuit",
      "definition": "The physical, plastic-coated card issued to clients during onboarding that contains daily phonetic challenge letters for the BCCC.",
      "policyContext": "BC-SEC-002"
    },
    {
      "term": "Sun Chip Confirmation Ceremony (BCCC)",
      "definition": "A high-security, video-based authentication ritual required for Tier-3 movements and system elevations.",
      "policyContext": "BC-SEC-002, BC-WIRE-001, BC-PROD-003"
    },
    {
      "term": "Beneficial Owner",
      "definition": "Any individual holding 25% or more of an entity account, or a single individual with significant managerial control.",
      "policyContext": "BC-ELIG-002, BC-COMP-002"
    },
    {
      "term": "Clean Room Device",
      "definition": "A hardware-fingerprinted computer or mobile device that has completed the 48-hour Enrollment Circuit and is free of remote-access software.",
      "policyContext": "BC-SEC-001"
    },
    {
      "term": "Cooling-Off Period",
      "definition": "A mandatory system-enforced wait time (e.g., 4, 24, or 72 hours) during which a requested change is 'Pending' and reversible but not executable.",
      "policyContext": "BC-SEC-001, BC-WIRE-001, BC-ACH-001, BC-EXCP-001"
    },
    {
      "term": "Cure Window",
      "definition": "The specific timeframe (standardized at 30 days) allowed for a client to rectify a policy breach, such as a balance drop below $10M.",
      "policyContext": "BC-ELIG-001"
    },
    {
      "term": "Delegate",
      "definition": "A third-party individual (e.g., Family Office CFO) granted limited, non-movement 'Observation Only' permissions on an account.",
      "policyContext": "BC-ELIG-002"
    },
    {
      "term": "Dormant Mode",
      "definition": "A system state triggered after 120 days of zero activity, requiring a physical BCCC to reactivate.",
      "policyContext": "BC-SEC-001"
    },
    {
      "term": "Enrollment Circuit",
      "definition": "The 48-hour technical process required to register a new Trusted Device or hardware key.",
      "policyContext": "BC-SEC-001"
    },
    {
      "term": "FIDO2 Token",
      "definition": "A hardware security key (e.g., YubiKey 5 Series) that serves as the only acceptable method for Sun Chip system access.",
      "policyContext": "BC-SEC-001, BC-SEC-002"
    },
    {
      "term": "Hard-Hold",
      "definition": "A non-negotiable, system-enforced 10-business-day hold placed on inbound funds from non-whitelisted institutions.",
      "policyContext": "BC-WIRE-001"
    },
    {
      "term": "ILV (Initial Lending Value)",
      "definition": "The maximum Loan-to-Value (LTV) ratio allowed at the inception of a Securities-Backed Line of Credit.",
      "policyContext": "BC-PROD-003"
    },
    {
      "term": "Jumbo PITI Reserves",
      "definition": "The requirement for 12 to 36 months of Principal, Interest, Taxes, and Insurance held in liquid reserves for large mortgages.",
      "policyContext": "BC-PROD-004"
    },
    {
      "term": "MLV (Maintenance Lending Value)",
      "definition": "The LTV threshold at which an automated margin call or forced liquidation is triggered on an SBLOC.",
      "policyContext": "BC-PROD-003"
    },
    {
      "term": "Normal Mode",
      "definition": "The standard operational state of an account where all verified devices have full read/write access to eligible features.",
      "policyContext": "BC-SEC-001"
    },
    {
      "term": "Recovery Mode",
      "definition": "A restricted state following the loss of a FIDO2 token, requiring a notarized affidavit and a 72-hour cooling-off period.",
      "policyContext": "BC-SEC-001"
    },
    {
      "term": "Restricted Mode",
      "definition": "A state where all money movement is disabled, typically triggered by a security alert or 'Geographic Anomaly'.",
      "policyContext": "BC-SEC-001, BC-ELIG-002"
    },
    {
      "term": "Service Circuit",
      "definition": "The predefined, immutable sequence of approvals and system checks required for a specific Policy ID.",
      "policyContext": "All BC-series policies"
    },
    {
      "term": "SOW-Enhanced",
      "definition": "A Tier-2 Source of Wealth verification requiring tax returns from the prior three fiscal years and independent audit trails.",
      "policyContext": "BC-ELIG-001, BC-COMP-002"
    },
    {
      "term": "Trusted Device",
      "definition": "A hardware-fingerprinted device that has successfully completed the 48-hour Enrollment Circuit and is registered to a specific Client ID.",
      "policyContext": "BC-SEC-001, BC-WIRE-001"
    },
    {
      "term": "Verified Mode",
      "definition": "A temporary elevated state (lasting 60 minutes) achieved after a BCCC, allowing for Tier-3 movements.",
      "policyContext": "BC-SEC-002, BC-WIRE-001"
    },
    {
      "term": "Whitelisted Recipient",
      "definition": "A third-party account that has been pre-verified through a $1.00 micro-deposit and 24-hour cooling-off.",
      "policyContext": "BC-WIRE-001"
    },
    {
      "term": "Investable Assets",
      "definition": "Cash, U.S. Treasuries, and marketable securities listed on major U.S. exchanges.",
      "policyContext": "BC-ELIG-001"
    },
    {
      "term": "Daily Average Balance (DAB)",
      "definition": "The sum of the end-of-day balances for the prior 30 days, divided by 30.",
      "policyContext": "BC-ELIG-001"
    },
    {
      "term": "U.S. Person",
      "definition": "A U.S. citizen or resident alien with a primary, physical U.S. residential address (no P.O. boxes or virtual offices).",
      "policyContext": "BC-ELIG-002"
    },
    {
      "term": "Geographic Tether",
      "definition": "The requirement that a client's digital footprint matches their declared U.S. service address.",
      "policyContext": "BC-ELIG-002"
    },
    {
      "term": "International Anomaly Mode",
      "definition": "A system state triggered when login attempts occur from IP addresses outside the U.S. for more than 48 consecutive hours.",
      "policyContext": "BC-ELIG-002"
    },
    {
      "term": "FIDO2 Enrollment",
      "definition": "The process of cryptographically binding a YubiKey 5 Series token to a specific Sun Chip User ID.",
      "policyContext": "BC-SEC-001"
    },
    {
      "term": "Device Fingerprinting",
      "definition": "The collection of hardware-level identifiers (MAC address, CPU serial, browser canvas) to create a 'Trusted Device' profile.",
      "policyContext": "BC-SEC-001"
    },
    {
      "term": "Challenge Letters",
      "definition": "Two phonetic letters (e.g., 'Alpha-Bravo') issued by the system and read by the client from 'The Biscuit'.",
      "policyContext": "BC-SEC-002"
    },
    {
      "term": "Signer Proximity",
      "definition": "The requirement that both signers of a joint account be visible on the video stream simultaneously.",
      "policyContext": "BC-SEC-002"
    },
    {
      "term": "Challenge String",
      "definition": "A sequence of five random numbers provided by the Banker during BCCC.",
      "policyContext": "BC-SEC-002"
    },
    {
      "term": "Response Code",
      "definition": "A code generated by the client's second FIDO2 key or secure physical 'Paper Token' during BCCC.",
      "policyContext": "BC-SEC-002"
    },
    {
      "term": "Duress Restricted Mode",
      "definition": "A system state triggered by failure in verbal clarity or background noise suggesting coaching or duress during BCCC.",
      "policyContext": "BC-SEC-002"
    },
    {
      "term": "Priority Window",
      "definition": "8:00 AM to 1:00 PM ET for same-day wire processing.",
      "policyContext": "BC-WIRE-001"
    },
    {
      "term": "Transaction Cooling-Off",
      "definition": "A 4-hour mandatory wait period for wires exceeding $2,000,000.00 unless recipient is Tier-1 Whitelisted for 180+ days.",
      "policyContext": "BC-WIRE-001"
    },
    {
      "term": "Third-Party Escrow",
      "definition": "Wires requiring a signed 'Closing Statement' or 'Purchase Agreement' upload prior to initiation.",
      "policyContext": "BC-WIRE-001"
    },
    {
      "term": "Restricted Industry",
      "definition": "A sector that requires 'Enhanced Monitoring' but is not outright banned.",
      "policyContext": "BC-COMP-001"
    },
    {
      "term": "Prohibited Industry",
      "definition": "A sector where no accounts may be opened, and no transactions may be processed.",
      "policyContext": "BC-COMP-001"
    },
    {
      "term": "Merchant Category Code (MCC)",
      "definition": "A standardized code identifying the type of business activity for compliance auditing.",
      "policyContext": "BC-COMP-001"
    },
    {
      "term": "Shell Company",
      "definition": "An entity with minimal operations used to obscure fund origins, subject to Tier-2 SOW-Enhanced verification.",
      "policyContext": "BC-COMP-001"
    },
    {
      "term": "Layering",
      "definition": "The practice of moving funds through multiple LLCs to hide prohibited origins, grounds for immediate account closure.",
      "policyContext": "BC-COMP-001"
    },
    {
      "term": "SOF (Source of Funds)",
      "definition": "Focuses on the origin of the specific money used for a single transaction.",
      "policyContext": "BC-COMP-002"
    },
    {
      "term": "SOW (Source of Wealth)",
      "definition": "Focuses on the accumulation of the client's total net worth over their entire career.",
      "policyContext": "BC-COMP-002"
    },
    {
      "term": "Sun Chip SOW Declaration",
      "definition": "A required form identifying the primary origin of the $10M+ balance for all initial deposits.",
      "policyContext": "BC-COMP-002"
    },
    {
      "term": "Flow of Funds",
      "definition": "A statement from the closing agent documenting the movement of funds in a business sale transaction.",
      "policyContext": "BC-COMP-002"
    },
    {
      "term": "MT799 Pre-Advice",
      "definition": "A SWIFT message providing advance notice of an international wire transfer.",
      "policyContext": "BC-COMP-002"
    },
    {
      "term": "Compliance Hold",
      "definition": "A 10-day mandatory hold triggered by discrepancy between 'Declared SOW' and 'Observed Transaction Patterns'.",
      "policyContext": "BC-COMP-002"
    },
    {
      "term": "Politically Exposed Persons (PEPs)",
      "definition": "Individuals subject to mandatory SOW-Enhanced verification regardless of transaction size.",
      "policyContext": "BC-COMP-002"
    },
    {
      "term": "Omnibus Account",
      "definition": "The primary central account at Sun Chip that holds pooled funds before distribution to the network.",
      "policyContext": "BC-PROD-001"
    },
    {
      "term": "Insured Network",
      "definition": "A group of up to 400 partner banks that each hold up to $250,000.00 of the client's cash.",
      "policyContext": "BC-PROD-001"
    },
    {
      "term": "Network Weighted Average",
      "definition": "The yield calculation based on the average rates across all partner banks in the sweep network.",
      "policyContext": "BC-PROD-001"
    },
    {
      "term": "Operational Buffer",
      "definition": "A minimum of $50,000.00 remaining in the local DDA for immediate debit availability.",
      "policyContext": "BC-PROD-001"
    },
    {
      "term": "Rung",
      "definition": "A specific maturity point in the Treasury ladder (e.g., 3-month, 6-month, 1-year).",
      "policyContext": "BC-PROD-002"
    },
    {
      "term": "Auto-Roll",
      "definition": "The reinvestment of principal into the longest rung of the ladder upon maturity.",
      "policyContext": "BC-PROD-002"
    },
    {
      "term": "Hold to Maturity",
      "definition": "A requirement that Treasuries within the ladder module cannot be sold early; liquidity must come from the SBLOC.",
      "policyContext": "BC-PROD-002"
    },
    {
      "term": "Liquidity Draw",
      "definition": "A notice filed 15 days prior to prevent reinvestment of maturing principal.",
      "policyContext": "BC-PROD-002"
    },
    {
      "term": "Force Majeure",
      "definition": "Documented extraordinary events permitting emergency liquidation of Treasury holdings with a 2% 'Disruption Fee'.",
      "policyContext": "BC-PROD-002"
    },
    {
      "term": "Pledge Agreement",
      "definition": "A notarized legal document required for initial SBLOC draws establishing collateral rights.",
      "policyContext": "BC-PROD-003"
    },
    {
      "term": "Regulation U Purpose Statement",
      "definition": "A required document certifying that SBLOC proceeds will not be used to purchase securities or pay off margin debt.",
      "policyContext": "BC-PROD-003"
    },
    {
      "term": "Control Agreement",
      "definition": "A document required for external assets pledged as SBLOC collateral.",
      "policyContext": "BC-PROD-003"
    },
    {
      "term": "Concentrated Stock",
      "definition": "A holding where a single ticker exceeds 20% of total portfolio value, subject to lower ILV (20-40%).",
      "policyContext": "BC-PROD-003"
    },
    {
      "term": "Margin Call",
      "definition": "A demand for additional collateral when LTV exceeds MLV, with a 24-hour cure window.",
      "policyContext": "BC-PROD-003"
    },
    {
      "term": "Automatic Liquidation",
      "definition": "System-executed market sell orders when LTV exceeds 90% for equities, without notice.",
      "policyContext": "BC-PROD-003"
    },
    {
      "term": "SOFR",
      "definition": "Secured Overnight Financing Rate, the base rate for variable SBLOC interest calculations.",
      "policyContext": "BC-PROD-003"
    },
    {
      "term": "PITI Reserves",
      "definition": "Liquid assets remaining after closing to cover Principal, Interest, Taxes, and Insurance.",
      "policyContext": "BC-PROD-004"
    },
    {
      "term": "Haircut",
      "definition": "The discount applied to non-cash assets when calculating reserves (e.g., stocks at 70%).",
      "policyContext": "BC-PROD-004"
    },
    {
      "term": "Debt-to-Income (DTI) Ratio",
      "definition": "The ratio of monthly debt obligations to gross monthly income, capped at 43% for Jumbo mortgages.",
      "policyContext": "BC-PROD-004"
    },
    {
      "term": "Reserve Tiers",
      "definition": "Tiered PITI reserve requirements based on loan amount: 12 months ($1.5M-$2M), 24 months ($2M-$5M), 36 months (>$5M).",
      "policyContext": "BC-PROD-004"
    },
    {
      "term": "High Liquidity Offset",
      "definition": "An exception allowing DTI expansion to 45% if client holds 60+ months of PITI reserves at Sun Chip.",
      "policyContext": "BC-PROD-004"
    },
    {
      "term": "Micro-Deposit Verification",
      "definition": "The process of sending two sub-$1.00 amounts to verify external account ownership.",
      "policyContext": "BC-ACH-001"
    },
    {
      "term": "R-Code",
      "definition": "Standardized NACHA return codes used by the Receiving Depository Financial Institution (RDFI).",
      "policyContext": "BC-ACH-001"
    },
    {
      "term": "Settlement Hold",
      "definition": "A mandatory 5-day hold on inbound ACH transfers exceeding $500,000.00.",
      "policyContext": "BC-ACH-001"
    },
    {
      "term": "Account Security Audit",
      "definition": "An immediate audit triggered by ACH returns with codes R05, R07, or R10, followed by 48-hour Restricted Mode.",
      "policyContext": "BC-ACH-001"
    },
    {
      "term": "Approved Debit Whitelist",
      "definition": "A list of third parties authorized to initiate inbound ACH debits (pulls) against the account.",
      "policyContext": "BC-ACH-001"
    },
    {
      "term": "International ACH (IAT)",
      "definition": "Cross-border ACH transfers, strictly prohibited and returned with code R81.",
      "policyContext": "BC-ACH-001"
    },
    {
      "term": "Written Statement of Unauthorized Debit (WSUD)",
      "definition": "A signed document required to dispute ACH return codes, filed within 60 calendar days.",
      "policyContext": "BC-ACH-001"
    },
    {
      "term": "Payroll Exception",
      "definition": "Higher outbound ACH limits for entity accounts with verified payroll providers (requires 3 months history).",
      "policyContext": "BC-ACH-001"
    },
    {
      "term": "Justification Narrative",
      "definition": "A required 500-word explanation of the necessity and risk mitigation for an exception request.",
      "policyContext": "BC-EXCP-001"
    },
    {
      "term": "Sunset Date",
      "definition": "The timestamp at which an exception automatically expires and the account reverts to standard rules.",
      "policyContext": "BC-EXCP-001"
    },
    {
      "term": "Risk Impact Score",
      "definition": "A score calculated by the OCRO required for all exception approvals.",
      "policyContext": "BC-EXCP-001"
    },
    {
      "term": "Master Exception Registry",
      "definition": "A log of all approved exceptions with unique Audit Receipt identifiers.",
      "policyContext": "BC-EXCP-001"
    },
    {
      "term": "Emergency Wire Outside Window (E-WOW)",
      "definition": "An exception request for wires outside standard processing hours, requiring notarized indemnity and BCCC with Head of Operations.",
      "policyContext": "BC-EXCP-001"
    },
    {
      "term": "Doctrine of Absolute Specificity",
      "definition": "Sun Chip's institutional philosophy that ambiguity is the primary vector for financial crime and operational error.",
      "policyContext": "Section 1.2"
    },
    {
      "term": "Zero-Trust Architecture",
      "definition": "A security model where no transaction is assumed legitimate based on login alone; requires hardware-bound identity and BCCC.",
      "policyContext": "Section 1.2"
    },
    {
      "term": "Sovereign-Grade Protection",
      "definition": "The highest level of security protection applied uniformly to all Sun Chip clients regardless of relationship length or status.",
      "policyContext": "Section 1.2"
    },
    {
      "term": "Retrieval-Augmented Generation (RAG)",
      "definition": "A knowledge base system requiring adherence to controlled vocabulary for internal and external communications.",
      "policyContext": "Section 1.3"
    },
    {
      "term": "Automatic Downgrade Circuit",
      "definition": "A system process triggered by failure to restore balance during Cure Window, resulting in loss of BCCC privileges and $5,000/month fee.",
      "policyContext": "BC-ELIG-001"
    },
    {
      "term": "Forced Closure Protocol",
      "definition": "Account termination process triggered by remaining in Warning Status for two consecutive quarters.",
      "policyContext": "BC-ELIG-001"
    },
    {
      "term": "Market Volatility Buffer",
      "definition": "An exception extending Cure Window to 60 days if DAB drop is due to 10%+ market correction in a single week.",
      "policyContext": "BC-ELIG-001"
    },
    {
      "term": "Intra-Family Funding",
      "definition": "An exception permitting temporary balance drops for up to 5 business days to fund a new Sun Chip account for a first-degree relative.",
      "policyContext": "BC-ELIG-001"
    },
    {
      "term": "Live Video Residency Affirmation",
      "definition": "A video-based verification required to exit International Anomaly Mode.",
      "policyContext": "BC-ELIG-002"
    },
    {
      "term": "Tier-1 Compliance Violation",
      "definition": "Use of VPN or Proxy to mask non-U.S. location, grounds for immediate account termination.",
      "policyContext": "BC-ELIG-002"
    },
    {
      "term": "Diplomatic Grace",
      "definition": "An exception for clients stationed abroad on official U.S. government business (requires SF-50 or equivalent).",
      "policyContext": "BC-ELIG-002"
    },
    {
      "term": "Travel Registry",
      "definition": "A pre-registration system for international travel up to 21 days (requires filing 48 hours prior to departure).",
      "policyContext": "BC-ELIG-002"
    },
    {
      "term": "Emergency Key Override",
      "definition": "An exception for FIDO2 key recovery in life-safety situations (requires police report and Senior Risk Officer approval).",
      "policyContext": "BC-SEC-001"
    },
    {
      "term": "Global Freeze",
      "definition": "A mandatory 72-hour freeze on all outbound transfers triggered by FIDO2 key removal or replacement.",
      "policyContext": "BC-SEC-001"
    },
    {
      "term": "Session Timeout",
      "definition": "A 15-minute inactivity limit requiring FIDO2 key reinsertion for continued access.",
      "policyContext": "BC-SEC-001"
    },
    {
      "term": "Read Only Mode",
      "definition": "A restricted access state for non-Trusted Devices lasting 48 hours before full access is granted.",
      "policyContext": "BC-SEC-001"
    },
    {
      "term": "Affidavit of Key Loss",
      "definition": "A notarized document required for FIDO2 key recovery.",
      "policyContext": "BC-SEC-001"
    },
    {
      "term": "Impaired Speech Exception",
      "definition": "An accommodation for clients with documented medical conditions (requires pre-filed ADA form and Power of Attorney).",
      "policyContext": "BC-SEC-002"
    },
    {
      "term": "Fraud Investigation Unit (FIU)",
      "definition": "The team responsible for escalation of BCCC failures.",
      "policyContext": "BC-SEC-002"
    },
    {
      "term": "Fee Waiver Exception",
      "definition": "Wire fee waiver available only if Policy BC-SLA-003 (Service Level Agreement) was breached in prior 30 days.",
      "policyContext": "BC-WIRE-001"
    },
    {
      "term": "Immediate Release Exception",
      "definition": "Expedited wire processing for Tier-1 Whitelisted recipients (Private Schools, Tax Authorities, Verified Law Firms).",
      "policyContext": "BC-WIRE-001"
    },
    {
      "term": "Tier-1 Whitelisted",
      "definition": "Recipients with 180+ days of successful transaction history, exempt from certain cooling-off requirements.",
      "policyContext": "BC-WIRE-001"
    },
    {
      "term": "Closing Statement",
      "definition": "A document required for real estate wire transactions (HUD-1 or Settlement Statement).",
      "policyContext": "BC-WIRE-001"
    },
    {
      "term": "Asset Purchase Agreement (APA)",
      "definition": "A signed document required for business acquisition wire transactions.",
      "policyContext": "BC-WIRE-001"
    },
    {
      "term": "IMAD/OMAD",
      "definition": "Input Message Accountability Data / Output Message Accountability Data for wire tracking.",
      "policyContext": "BC-WIRE-001"
    },
    {
      "term": "Beneficiary Name Match Score",
      "definition": "A metric measuring the accuracy of recipient name verification in wire transactions.",
      "policyContext": "BC-WIRE-001"
    },
    {
      "term": "Crypto-Fiat Gateway",
      "definition": "Exchanges like Coinbase and Kraken where outbound transactions are automatically blocked.",
      "policyContext": "BC-COMP-001"
    },
    {
      "term": "Banned Gateway Database",
      "definition": "A list of prohibited transaction destinations updated every 24 hours.",
      "policyContext": "BC-COMP-001"
    },
    {
      "term": "Suspicious Activity Review (SAR)",
      "definition": "A compliance review triggered by transactions to restricted industries.",
      "policyContext": "BC-COMP-001"
    },
    {
      "term": "Art and Antiquities Exception",
      "definition": "Permitted only with 3rd party appraisal and 'Provenance Certificate' for transactions exceeding $1M.",
      "policyContext": "BC-COMP-001"
    },
    {
      "term": "Industry Risk Rating",
      "definition": "A classification assigned to client business activities for compliance monitoring.",
      "policyContext": "BC-COMP-001"
    },
